    expect(validator.validate('hello', '\\d+')).toBe(false);
  });

  test('should reuse cached patterns', () => {
    const validator = new PatternValidator();
    const pattern = '[a-z]+';

    validator.validate('test', pattern);
    validator.validate('test2', pattern);

    expect(validator.validate('test3', pattern)).toBe(true);
  });
});

