// Global cache for all compiled regex patterns
const regexCache = {};

class PatternValidator {
  validate(text, pattern) {
    // Check cache first
    if (!regexCache[pattern]) {
      // Compile and cache the regex
      regexCache[pattern] = new RegExp(pattern);
    }

    // Use cached regex
    return regexCache[pattern].test(text);
  }
}

module.exports = PatternValidator;
EOF
